{
    "level": "A2–B1",
    "intro": "]W tym temacie poznasz zasady używania przedimka <strong>the</strong> z <strong>nazwami geograficznymi</strong> - kiedy jest to potrzebne i kiedy można się bez niego obejść.",
    "rules": [
        {
            "label": "Bez ",
            "color": "emerald",
            "text": "<strong>Większość krajów i miast</strong> — bez przedimka:",
            "example": "Ukraina, Londyn, Paryż, Włochy"
        },
        {
            "label": "Z",
            "color": "blue",
            "text": "<strong>Oceany, rzeki, góry</strong> — z artykułem:",
            "example": " Pacyfik, Dniepr, Alpy"
        },
        {
            "label": "Wyjątki",
            "color": "amber",
            "text": "<strong>Kraje Unii</strong> — z artykułem:",
            "example": "USA, Wielka Brytania, Holandia"
        }
    ]
}

{
    "title": "1. Zasada ogólna",
    "intro": "Artykuł z nazwami geograficznymi zależy od typu obiektu:",
    "items": [
        {
            "label": "Bez",
            "title": "Kraje, miasta, kontynenty",
            "subtitle": "Ukraina, Londyn, Europa – większość nie potrzebuje artykułu"
        },
        {
            "label": "Z ",
            "title": "Oceany, rzeki, góry",
            "subtitle": "Pacyfik, Dniepr, Alpy – zawsze z przedimkiem"
        },
        {
            "label": "Wyjątki",
            "title": "Związki i liczba mnoga",
            "subtitle": "USA, Wielka Brytania, Filipiny – specjalne przypadki"
