        {
            "label": "Większość krajów – Ø",
            "color": "emerald",
            "description": "<strong>Większość krajów</strong> używa słowa <strong>bez przedimka</strong>.",
            "examples": [
                {
                    "en": "Ukraina, Polska, Niemcy, Francja",
                    "ua": "Ukraina, Polska, Niemcy, Francja"
                },
                {
                    "en": "Włochy, Hiszpania, Portugalia, Grecja",
                    "ua": "Włochy, Hiszpania, Portugalia, Grecja"
                },
                {
                    "en": "Japonia, Chiny, Indie, Australia",
                    "ua": "Japonia, Chiny, Indie, Australia"
