        {
            "label": "Kraje Unii THE",
            "color": "blue",
            "description": "<strong>Kraje Unii</strong> lub nazwy w <strong>liczbie mnogiej</strong> — z przedimkiem <strong>the</strong>.",
            "examples": [
                {
                    "en": "Stany Zjednoczone (USA)",
                    "ua": "Stany Zjednoczone (USA)"
                },
                {
                    "en": "Wielka Brytania (Wielka Brytania)",
                    "ua": "Wielka Brytania (Wielka Brytania)"
                },
                {
                    "en": "Zjednoczone Emiraty Arabskie (ZEA)",
                    "ua": "Zjednoczone Emiraty Arabskie (ZEA)"
                },
                {
                    "en": " Holandia",
                    "ua": "Holandia"
                }
            ]
        },
        {
            "label": "Dlaczego THE?",
            "color": "amber",
            "description": "Artykuł <strong>the</strong> jest wymagany, jeśli:",
            "examples": [
                {
                    "en": "1. Nazwa zawiera „Stany”, „Królestwo”, „Republikę”",
                    "ua": "Stany Zjednoczone, Republikę Czeską"
                },
                {
                    "en": "2. Nazwa mnoga",
                    "ua": "Holandia, Filipiny"
                },
                {
                    "en": "3. Historyczna nazwa z Unii/Federacji",
                    "ua": "Związku Radzieckiego (historyczna)"
                }
            ],
            "note": "📌 Wyjątki: Gambia, Kongo, Sudan (historyczna)."
        }
    ]
}

